1	/**
2	 * LayerInfinite MCP Server — rest-client.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Thin HTTP client that proxies calls to the LayerInfinite REST API.
5	 * Handles auth headers, timeouts, retries, and structured error responses.
6	 *
7	 * Production hardening:
8	 *   - Exponential backoff retry for transient failures (503, 429, timeouts)
9	 *   - Structured request/response logging
10	 *   - Native fetch() — zero external dependencies
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import type { LIConfig } from './config.js';
15	import { logger } from './logger.js';
16	
17	/** Standard error shape returned by the LI REST API. */
18	export interface LIApiError {
19	  error: string;
20	  code: string;
21	  message?: string;
22	  details?: unknown;
23	}
24	
25	/** Successful response wrapper. */
26	export interface LIApiResponse<T> {
27	  ok: true;
28	  status: number;
29	  data: T;
30	}
31	
32	/** Failed response wrapper. */
33	export interface LIApiErrorResponse {
34	  ok: false;
35	  status: number;
36	  error: LIApiError;
37	}
38	
39	export type LIResult<T> = LIApiResponse<T> | LIApiErrorResponse;
40	
41	const DEFAULT_TIMEOUT_MS = 15_000;
42	
43	/** HTTP status codes that are safe to retry. */
44	const RETRYABLE_STATUS_CODES = new Set([429, 502, 503, 504]);
45	
46	/** Max retries for transient failures. */
47	const MAX_RETRIES = 2;
48	
49	/** Base delay for exponential backoff (ms). */
50	const BASE_RETRY_DELAY_MS = 500;
51	
52	export class RestClient {
53	  private readonly baseUrl: string;
54	  private readonly headers: Record<string, string>;
55	  private readonly log = logger.forTool('rest-client');
56	
57	  constructor(config: LIConfig) {
58	    this.baseUrl = config.baseUrl;
59	    this.headers = {
60	      'X-API-Key': config.apiKey,
61	      'Content-Type': 'application/json',
62	      'User-Agent': '@layerinfinite/mcp-server/1.0.0',
63	    };
64	  }
65	
66	  /** GET request to the LI REST API. */
67	  async get<T>(path: string, params?: Record<string, string>): Promise<LIResult<T>> {
68	    const url = new URL(`${this.baseUrl}${path}`);
69	    if (params) {
70	      for (const [key, value] of Object.entries(params)) {
71	        if (value !== undefined && value !== '') {
72	          url.searchParams.set(key, value);
73	        }
74	      }
75	    }
76	
77	    return this.requestWithRetry<T>(url.toString(), { method: 'GET' });
78	  }
79	
80	  /** POST request to the LI REST API. */
81	  async post<T>(path: string, body: Record<string, unknown>): Promise<LIResult<T>> {
82	    const url = `${this.baseUrl}${path}`;
83	    return this.requestWithRetry<T>(url, {
84	      method: 'POST',
85	      body: JSON.stringify(body),
86	    });
87	  }
88	
89	  /** PUT request to the LI REST API. */
90	  async put<T>(path: string, body: Record<string, unknown>): Promise<LIResult<T>> {
91	    const url = `${this.baseUrl}${path}`;
92	    return this.requestWithRetry<T>(url, {
93	      method: 'PUT',
94	      body: JSON.stringify(body),
95	    });
96	  }
97	
98	  /**
99	   * Request with exponential backoff retry for transient failures.
100	   * Retries on: 429, 502, 503, 504, TIMEOUT, NETWORK_ERROR
101	   * Does NOT retry on: 400, 401, 403, 404, 409 (client errors are permanent)
102	   */
103	  private async requestWithRetry<T>(url: string, init: RequestInit): Promise<LIResult<T>> {
104	    let lastResult: LIResult<T> | null = null;
105	
106	    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
107	      if (attempt > 0) {
108	        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
109	        this.log.warn('Retrying request', {
110	          url,
111	          method: init.method,
112	          attempt: attempt + 1,
113	          delay_ms: delay,
114	        });
115	        await this.sleep(delay);
116	      }
117	
118	      const result = await this.request<T>(url, init);
119	
120	      // Success — return immediately
121	      if (result.ok) return result;
122	
123	      lastResult = result;
124	
125	      // Check if the error is retryable
126	      const isRetryableStatus = RETRYABLE_STATUS_CODES.has(result.status);
127	      const isRetryableError = result.error.code === 'TIMEOUT' || result.error.code === 'NETWORK_ERROR';
128	
129	      if (!isRetryableStatus && !isRetryableError) {
130	        // Client error (400, 401, 403, 404) — don't retry
131	        break;
132	      }
133	    }
134	
135	    // All retries exhausted — return the last error
136	    return lastResult!;
137	  }
138	
139	  private async request<T>(url: string, init: RequestInit): Promise<LIResult<T>> {
140	    const controller = new AbortController();
141	    const timeout = setTimeout(() => controller.abort(), DEFAULT_TIMEOUT_MS);
142	    const startMs = Date.now();
143	
144	    try {
145	      const response = await fetch(url, {
146	        ...init,
147	        headers: { ...this.headers, ...(init.headers as Record<string, string> ?? {}) },
148	        signal: controller.signal,
149	      });
150	
151	      const latencyMs = Date.now() - startMs;
152	      const contentType = response.headers.get('content-type') ?? '';
153	      const isJson = contentType.includes('application/json');
154	
155	      if (response.ok) {
156	        const data = isJson ? (await response.json()) as T : ({} as T);
157	        this.log.debug('API response', {
158	          method: init.method,
159	          url,
160	          status: response.status,
161	          latency_ms: latencyMs,
162	        });
163	        return { ok: true, status: response.status, data };
164	      }
165	
166	      const errorBody = isJson
167	        ? (await response.json()) as LIApiError
168	        : { error: 'API Error', code: 'UNKNOWN', message: await response.text() };
169	
170	      this.log.warn('API error', {
171	        method: init.method,
172	        url,
173	        status: response.status,
174	        latency_ms: latencyMs,
175	        error_code: errorBody.code,
176	      });
177	
178	      return { ok: false, status: response.status, error: errorBody };
179	    } catch (err) {
180	      const latencyMs = Date.now() - startMs;
181	
182	      if (err instanceof DOMException && err.name === 'AbortError') {
183	        this.log.error('Request timeout', {
184	          method: init.method,
185	          url,
186	          timeout_ms: DEFAULT_TIMEOUT_MS,
187	          latency_ms: latencyMs,
188	        });
189	        return {
190	          ok: false,
191	          status: 0,
192	          error: { error: 'Request timed out', code: 'TIMEOUT', message: `Request to ${url} timed out after ${DEFAULT_TIMEOUT_MS}ms` },
193	        };
194	      }
195	
196	      const message = err instanceof Error ? err.message : String(err);
197	      this.log.error('Network error', {
198	        method: init.method,
199	        url,
200	        latency_ms: latencyMs,
201	        error: message,
202	      });
203	      return {
204	        ok: false,
205	        status: 0,
206	        error: { error: 'Network error', code: 'NETWORK_ERROR', message },
207	      };
208	    } finally {
209	      clearTimeout(timeout);
210	    }
211	  }
212	
213	  private sleep(ms: number): Promise<void> {
214	    return new Promise(resolve => setTimeout(resolve, ms));
215	  }
216	}
