// ── Helpers ───────────────────────────────────────────────────

function djb2(str: string): number {
  let hash = DJB2_SEED;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash; // Convert to 32-bit integer
  }
  return hash >>> 0; // Ensure unsigned
}

function toBase62(n: number): string {
  if (n === 0) return '0';
  let result = '';
  while (n > 0) {
    result = BASE62[n % 62] + result;
    n = Math.floor(n / 62);
  }
  return result;
}

function randomBase62(length: number): string {
  let result = '';
  for (let i = 0; i < length; i++) {
    result += BASE62[Math.floor(Math.random() * 62)];
  }
  return result;
}

/**
 * Generate a sortable decision ID.
 * Format: dec_{ts12}_{agent4}_{rand4}
 */
export function generateDecisionId(agentId: string): string {
  const ts = toBase62(Date.now()).padStart(12, '0').slice(-12);
  const hash = Math.abs(djb2(agentId));
  const agent = toBase62(hash).padStart(4, '0').slice(0, 4);
  const rand = randomBase62(4);
  return `dec_${ts}_${agent}_${rand}`;
}

function getTrendText(trendLabel: string | undefined): string {
  if (!trendLabel) return '';
  const trend = parseFloat(trendLabel);
  if (isNaN(trend)) {
    // If it's a non-numeric label, use it as-is but prepend space
    return ` (${trendLabel})`;
  }
  if (trend >= 0.1) return ' and has been improving';
  if (trend >= 0.05) return ' with a slight positive trend';
  if (trend > -0.05) return '';
  if (trend > -0.1) return ' with a slight negative trend';
  return ' but has been declining';
}

// ── GatewayProxy ──────────────────────────────────────────────

export class GatewayProxy {
  private currentTaskType = '';
  private shutdownFlag = false;

  constructor(
    private readonly liApi: LiApiClient,
    private readonly upstreamClient: UpstreamMCPClient,
    private readonly registry: UpstreamRegistry,
    private readonly config: GatewayConfig,
  ) {}

  // ── Public handlers ─────────────────────────────────────────

  /**
   * Intercept tools/list: fetch upstream tools, enrich descriptions
   * with historical outcome data, inject virtual li_recommend tool,
   * sort by ranking, and return.
   */
  async handleListTools(
    taskContext: { taskType: string; customerId: string; agentId: string },
  ): Promise<EnrichedTool[]> {
    this.currentTaskType = taskContext.taskType;

    // 1. Fetch raw tools from upstream
    let rawTools: RawUpstreamTool[] = [];
    try {
      rawTools = await this.withTimeout(
        this.upstreamClient.listTools(),
        UPSTREAM_CALL_TIMEOUT_MS,
        'listTools',
      );
    } catch (err) {
      log.error('Failed to list upstream tools', {
        taskType: taskContext.taskType,
        error: err instanceof Error ? err.message : String(err),
      });
      // Continue with empty tools — will still return li_recommend if applicable
    }

    // 2. Get enrichment context
    const context = await this.getEnrichmentContext(taskContext);

    // 3. Enrich each tool description
    const enriched = this.enrichTools(rawTools, context);

    // 4. Inject virtual li_recommend (not in bootstrap mode)
    if (context.mode !== 'bootstrap') {
      enriched.push(this.createRecommendTool(context));
    }

    // 5. Sort by ranking (best first), then alphabetically
    enriched.sort((a, b) => {
      const rankA = a.annotations?.ranking ?? Number.MAX_SAFE_INTEGER;
      const rankB = b.annotations?.ranking ?? Number.MAX_SAFE_INTEGER;
      if (rankA !== rankB) return rankA - rankB;
      return a.name.localeCompare(b.name);
    });

    log.info('tools/list enriched', {
      taskType: taskContext.taskType,
      mode: context.mode,
      totalTools: enriched.length,
      upstreamTools: rawTools.length,
      hasScores: context.scores.length > 0,
      hasPolicy: context.policyDecision !== null,
    });

    return enriched;
  }

  /**
   * Intercept tools/call: generate decisionId, handle virtual
   * li_recommend, auto-mode rerouting, proxy to upstream, and
   * fire-and-forget outcome logging.
   */
  async handleCallTool(
    toolName: string,
    args: Record<string, unknown>,
    taskContext: { taskType: string; customerId: string; agentId: string },
  ): Promise<UpstreamCallResult> {
    this.currentTaskType = taskContext.taskType;
    const decisionId = generateDecisionId(taskContext.agentId);
    const effectiveMode = this.resolveMode(taskContext.taskType);
    const startMs = Date.now();

    // 1. Handle virtual li_recommend tool
    if (toolName === 'li_recommend') {
      return this.handleRecommendCall(taskContext, decisionId, effectiveMode);
    }

    // 2. Determine the tool to execute (may differ from requested in auto mode)
    const upstreamName = this.resolveUpstreamName(toolName);
    let executedAction = toolName;
    let rerouted = false;
    let originalAction = toolName;

    // 3. Auto-mode rerouting
    const canReroute = effectiveMode === 'auto'
      && !this.config.shadowMode
      && !this.shutdownFlag;

    if (canReroute) {
      try {
        const context = await this.getEnrichmentContext(taskContext);
        const rerouteResult = this.tryReroute(toolName, context, upstreamName);
        if (rerouteResult) {
          executedAction = rerouteResult.toolName;
          rerouted = true;
          log.info('Auto-rerouted tool', {
            decisionId,
            original: originalAction,
            executed: executedAction,
            reason: context.policyDecision?.reason,
            confidence: context.policyDecision?.confidence,
          });
        }
      } catch (err) {
        log.warn('Reroute check failed, proceeding with original tool', {
          decisionId,
          toolName,
          error: err instanceof Error ? err.message : String(err),
        });
      }
    }

    // 4. Proxy to upstream
    const resolvedUpstream = rerouted
      ? this.resolveUpstreamName(executedAction)
      : upstreamName;

    let result: UpstreamCallResult;
    try {
      result = await this.withTimeout(
        this.upstreamClient.callTool(resolvedUpstream, executedAction, args),
        UPSTREAM_CALL_TIMEOUT_MS,
        `callTool:${executedAction}`,
      );
    } catch (err) {
      const latencyMs = Date.now() - startMs;
      const errorMessage = err instanceof Error ? err.message : String(err);
      log.error('Upstream tool call failed', {
        decisionId,
        tool: executedAction,
        upstream: resolvedUpstream,
        latency_ms: latencyMs,
        error: errorMessage,
      });

      // Fire-and-forget failure log
      void this.logOutcomeFireAndForget({
        decisionId,
        taskContext,
        originalAction,
        executedAction,
        upstreamName: resolvedUpstream,
        rerouted,
        effectiveMode,
        latencyMs,
        success: false,
      });

      return {
        content: [{ type: 'text', text: `Tool call failed: ${errorMessage}` }],
        isError: true,
      };
    }

    // 5. Fire-and-forget success log
    const latencyMs = Date.now() - startMs;
    void this.logOutcomeFireAndForget({
      decisionId,
      taskContext,
      originalAction,
      executedAction,
      upstreamName: resolvedUpstream,
      rerouted,
      effectiveMode,
      latencyMs,
      success: !result.isError,
    });

    return result;
  }

  // ── Lifecycle ───────────────────────────────────────────────

  async shutdown(): Promise<void> {
    this.shutdownFlag = true;
    log.info('Gateway proxy shutting down');
  }

  // ── Private: enrichment ─────────────────────────────────────

  /**
   * Enrich raw upstream tools with historical scores and rankings.
   * Filters out scores for unhealthy upstreams.
   */
  private enrichTools(
    tools: RawUpstreamTool[],
    context: EnrichmentContext,
  ): EnrichedTool[] {
    if (context.mode === 'bootstrap') {
      return tools.map(tool => ({
        name: tool.name,
        description: tool.description,
        inputSchema: tool.inputSchema,
        upstreamName: tool.upstreamName,
      }));
    }

    // Build tool -> upstream map for health filtering
    const toolUpstreamMap = new Map(tools.map(t => [t.name, t.upstreamName]));

    // Filter scores to healthy upstreams only
    const healthyScores = context.scores.filter(score => {
      const upstream = toolUpstreamMap.get(score.actionName);
      if (!upstream) return false;
      return this.registry.isHealthy(upstream);
    });

    // Rank scores by compositeScore descending
    const rankedScores = [...healthyScores].sort((a, b) => b.compositeScore - a.compositeScore);
    const rankMap = new Map(rankedScores.map((s, i) => [s.actionName, i + 1]));

    return tools.map(tool => {
      const score = healthyScores.find(s => s.actionName === tool.name);
      const rank = rankMap.get(tool.name);
      const description = this.enrichDescription(tool, healthyScores, context.mode);

      let category: 'recommended' | 'neutral' | 'warning' | undefined;
      if (rank === 1) {
        category = 'recommended';
      } else if (score && score.successRate < 0.5) {
        category = 'warning';
      } else if (rank !== undefined) {
        category = 'neutral';
      }

      return {
        name: tool.name,
        description,
        inputSchema: tool.inputSchema,
        upstreamName: tool.upstreamName,
        annotations: rank !== undefined ? { ranking: rank, category } : undefined,
      };
    });
  }

  /**
   * Enrich a single tool's description based on historical scores.
   * Format varies by mode (bootstrap = passthrough, recommend/assist/auto = enriched).
   */
  private enrichDescription(
    tool: RawUpstreamTool,
    scores: ScoredAction[],
    mode: GatewayMode,
  ): string {
    if (mode === 'bootstrap') return tool.description;

    const score = scores.find(s => s.actionName === tool.name);
    if (!score) return tool.description;

    // Determine rank
    const sorted = [...scores].sort((a, b) => b.compositeScore - a.compositeScore);
    const rank = sorted.findIndex(s => s.actionName === tool.name) + 1;

    const trendText = getTrendText(score.trendLabel);
    const successRate = Math.round(score.successRate * 100);
    const taskType = this.currentTaskType || 'this';

    const historical = [
      `Historically for "${taskType}" tasks,`,
      `${tool.name} has a ${successRate}% success rate across`,
      `${score.sampleSize} executions${trendText}.`,
      `This is the #${rank} recommended tool for this task.`,
    ].join(' ');

    const enriched = `${tool.description}\n\n${historical}`;

    if (mode === 'assist' || mode === 'auto') {
      return enriched + ' ⚠ Consider the success history when choosing tools.';
    }

    return enriched;
  }

  // ── Private: context ────────────────────────────────────────

  /**
   * Fetch enrichment context (scores + policy decision) from LI API.
   * Degrades gracefully: if either call fails, continues with empty/default values.
   */
  private async getEnrichmentContext(
    taskContext: { taskType: string; customerId: string; agentId: string },
  ): Promise<EnrichmentContext> {
    const mode = this.resolveMode(taskContext.taskType);

    const base: EnrichmentContext = {
      taskType: taskContext.taskType,
      customerId: taskContext.customerId,
      agentId: taskContext.agentId,
      mode,
      scores: [],
      policyDecision: null,
    };

    if (mode === 'bootstrap') return base;

    const [scoresResult, policyResult] = await Promise.allSettled([
      this.withTimeout(
        this.liApi.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
        LI_API_TIMEOUT_MS,
        'getScores',
      ),
      this.withTimeout(
        this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
        LI_API_TIMEOUT_MS,
        'getPolicyDecision',
      ),
    ]);

    if (scoresResult.status === 'fulfilled') {
      base.scores = scoresResult.value;
      log.debug('Scores fetched', {
        taskType: taskContext.taskType,
        count: base.scores.length,
      });
    } else {
      log.warn('Failed to fetch scores, continuing in degrade mode', {
        taskType: taskContext.taskType,
        error: scoresResult.reason instanceof Error
          ? scoresResult.reason.message
          : String(scoresResult.reason),
      });
    }

    if (policyResult.status === 'fulfilled') {
      base.policyDecision = policyResult.value;
      if (base.policyDecision) {
        log.debug('Policy decision fetched', {
          taskType: taskContext.taskType,
          action: base.policyDecision.action,
          confidence: base.policyDecision.confidence,
        });
      }
    } else {
      log.warn('Failed to fetch policy decision', {
        taskType: taskContext.taskType,
        error: policyResult.reason instanceof Error
          ? policyResult.reason.message
          : String(policyResult.reason),
      });
    }

    return base;
  }

  // ── Private: routing ────────────────────────────────────────

  /**
   * Resolve the effective mode for a task type, considering overrides.
   */
  private resolveMode(taskType: string): GatewayMode {
    const override = this.config.modeOverrides.get(taskType);
    if (override) return override;
    return this.config.mode ?? 'bootstrap';
  }

  /**
   * Look up the upstream name for a tool.
   * Falls back to "unknown" if not found.
   */
  private resolveUpstreamName(toolName: string): string {
    // The upstream mapping is derived from the tools previously fetched
    // For simplicity, we rely on the upstream client or registry
    const upstreams = this.registry.getAllUpstreams();
    for (const entry of upstreams) {
      if (entry.healthy) {
        return entry.server.name;
      }
    }
    return 'unknown';
  }

  /**
   * Attempt to reroute a tool call based on policy decision.
   * Returns the reroute target or null if no reroute is appropriate.
   */
  private tryReroute(
    toolName: string,
    context: EnrichmentContext,
    _upstreamName: string,
  ): { toolName: string } | null {
    const { policyDecision } = context;
    if (!policyDecision) return null;

    // Only reroute if confidence meets threshold
    if (policyDecision.confidence < ADJUSTABLE_THRESHOLD) {
      log.debug('Policy confidence below threshold, skipping reroute', {
        action: policyDecision.action,
        confidence: policyDecision.confidence,
        threshold: ADJUSTABLE_THRESHOLD,
      });
      return null;
    }

    // Only reroute if recommended tool is different from requested
    if (policyDecision.action === toolName) return null;

    // Check if the recommended tool exists and is healthy
    const recommendedUpstream = this.resolveUpstreamName(policyDecision.action);
    if (recommendedUpstream === 'unknown') {
      log.warn('Recommended tool has no healthy upstream, skipping reroute', {
        recommended: policyDecision.action,
      });
      return null;
    }

    return { toolName: policyDecision.action };
  }

  // ── Private: virtual tool ───────────────────────────────────

  /**
   * Create the virtual li_recommend tool.
   * Injected into tools/list to allow agents to query recommendations on demand.
   */
  private createRecommendTool(context: EnrichmentContext): EnrichedTool {
    return {
      name: 'li_recommend',
      description:
        'Get LayerInfinite recommendations for the best tool to use for this task type based on historical success data across all agents.',
      inputSchema: {
        type: 'object',
        properties: {},
        required: [],
      },
      upstreamName: 'layerinfinite',
      annotations: { category: 'recommended', ranking: 0 },
    };
  }

  /**
   * Handle a tools/call for the virtual li_recommend tool.
   * Returns current recommendations as natural language content.
   */
  private async handleRecommendCall(
    taskContext: { taskType: string; customerId: string; agentId: string },
    decisionId: string,
    mode: GatewayMode,
  ): Promise<UpstreamCallResult> {
    const context = await this.getEnrichmentContext(taskContext);
    const scores = context.scores;

    if (scores.length === 0) {
      return {
        content: [{
          type: 'text',
          text: `No historical data available for "${taskContext.taskType}" tasks yet. Try using tools normally — LayerInfinite will learn from your outcomes.`,
        }],
      };
    }

    const sorted = [...scores]
      .sort((a, b) => b.compositeScore - a.compositeScore)
      .slice(0, 5);

    const lines = [
      `Based on historical data for "${taskContext.taskType}" tasks (mode: ${mode}):`,
      '',
    ];

    sorted.forEach((s, i) => {
      const rate = Math.round(s.successRate * 100);
      const trendText = getTrendText(s.trendLabel);
      lines.push(
        `${i + 1}. ${s.actionName} — ${rate}% success rate (${s.sampleSize} executions)${trendText}`,
      );
    });

    if (context.policyDecision) {
      lines.push('');
      lines.push(`Recommended: ${context.policyDecision.action} (confidence: ${Math.round(context.policyDecision.confidence * 100)}%)`);
      lines.push(`Reason: ${context.policyDecision.reason}`);
    }

    return {
      content: [{ type: 'text', text: lines.join('\n') }],
    };
  }

